-- AUTO: реальные кейсы ФЛ по 7 играм (73 шт). Запусти в Supabase → SQL Editor → Run.
-- Показывается игрокам как задание; эталонные ответы сюда НЕ входят.
delete from public.cases;
insert into public.cases (game_id, ord, title, difficulty, body) values
  ('detective', 1, 'Блокировка карты в поездке', 'Средний', 'Я в Стамбуле, мне нужно оплатить отель — карта не проходит! Я пытался три раза, теперь вообще не знаю, что делать. Мне сказали, что надо подключить уведомления о поездке заранее. Но я этого не знал! Почему банк не предупреждает? Мне нужны деньги прямо сейчас!'),
  ('detective', 2, 'Кредит одобрен, денег нет', 'Средний', 'Я оформил кредит онлайн, у меня уже сняли страховку — 4 800 рублей. Но деньги на счёт так и не пришли! Прошло уже два дня. Я несколько раз заходил в приложение — там написано «заявка на рассмотрении». Это что вообще такое? Мне деньги нужны были вчера, я уже не знаю к кому обращаться.'),
  ('detective', 3, 'Перевод по ошибочным реквизитам', 'Сложный', 'Я только что перевела деньги маме — 15 000 рублей. Но я перепутала реквизиты. Деньги ушли какому-то незнакомому человеку. Можно ли их вернуть? Я уже плачу, не знаю что делать. Это все мои деньги на этот месяц.'),
  ('detective', 4, 'Кредит пропал после смены паспорта', 'Сложный', 'Здравствуйте, такая проблема: у меня есть кредит, но я его в приложении не вижу, а мне нужно оплатить его . А сумму я не знаю… Я меняла фамилию, паспорт поменяла, возможно, из-за этого и не видно мой кредит? Можно это как-то исправить?'),
  ('detective', 5, 'Не пришёл межбанковский перевод', 'Средний', 'Здравствуйте! Был отправлен перевод по номеру моего счета от ОЗОН-банка. Прошло уже 2 дня, но денег так и нет! В ОЗОН-банке сказали, что платеж отправлен и проблема на стороне вашего банка! Прошу решить мой вопрос!'),
  ('detective', 6, 'Комиссия за бесплатную карту', 'Средний', 'Здравствуйте! Подскажите,  за что у меня сняли деньги за обслуживание кредитной карты?! У меня карта без платы за обслуживание. Я это уже уточняла у вас несколько раз. И при оформлении меня предупреждали, что карта бесплатная. Она у меня уже 3-ий год, и сейчас впервые что-то списали. Верните деньги!'),
  ('detective', 7, 'Пропала категория кэшбэка', 'Средний', 'Здравствуйте! Я очень огорчена. Я специально сделала вашу дебетовую своей зарплатной, потому что мне всегда нравился ваш кэшбэк, в особенности 1% со всех покупок. Сейчас зашла выбрать категории кэшбека на май, а там моей любимой категории 1% на все покупки нет. Это в честь чего такие нововведения? Я буду уходить в другой банк с таким отношением, и зарплату переведу на другую карту. Просто кошмар.'),
  ('detective', 8, 'Банкомата нет по адресу', 'Лёгкий', 'Добрый день, где банкомат в г. Краснодар по адресу Мачуги, 2 в Краснодаре? Был банкомат на Мачуги, 4. Я пришла — его там нет. Посмотрела в приложении ближайший на Мачуги, 2. Пришла — его и тут нет. Что это такое вообще творится? Почему вы вводите клиента в заблуждение? Срочно нужно снять наличные с карты.'),
  ('detective', 9, 'Отказ в кредитных каникулах', 'Сложный', 'Я хотел бы оформить каникулы по госпрограмме по причине снижения дохода. Но мне сказали, что это невозможно, потому что я уже оформлял их ранее по № 106‑ФЗ в 22 году. Что мне делать? Мне нечем платить за кредит!'),
  ('detective', 10, 'Попытка взлома мошенниками', 'Сложный', 'Меня пытаются взломать мошенники! Пытались оформить с ребенком с моего телефона кредит, пока меня не было дома, и теперь у меня полно смс с кодами и просьбой продолжить оформление. Помогите!'),
  ('noforward', 1, 'Комиссия при подписке Альфа-Смарт', 'Средний', '«Мне сняли 190 рублей комиссию за перевод, хотя я уже три года клиент банка! У меня подключена подписка Альфа-Смарт — там переводы должны быть бесплатными. Объясните что происходит и верните деньги!»'),
  ('noforward', 2, 'Приложение не работает, срочный платёж', 'Средний', '«У меня не открывается приложение уже час. Мне срочно нужно оплатить аренду — сегодня последний день, иначе штраф, а яне могу перевести деньги своему арендодателю! Что мне делать? Я не могу ждать пока вы там что-то починяете!»'),
  ('noforward', 3, 'Пропал телефон с мобильным банком', 'Сложный', 'У меня пропал телефон, на котором был установлен мобильный банкинг. Через него я получаю SMS‑уведомления и пуш‑сообщения о всех операциях по карте и счету. Сейчас боюсь, что кто‑то может воспользоваться моими данными. Пожалуйста, срочно помогите!'),
  ('noforward', 4, 'Двойное списание платежа', 'Сложный', '«Сегодня с меня списали платёж два раза — 43 000 рублей! Это что, шутки?! У меня сейчас минус на счёте. Верните деньги немедленно, иначе я пишу жалобу в ЦБ!»'),
  ('noforward', 5, 'Операция без уведомления', 'Сложный', '«Я только что увидел в выписке операцию в Яндексе на 8 000 рублей, которую я не делал. Я не получил никакого уведомления! Как это вообще возможно? Уведомления у меня подключены.»'),
  ('noforward', 6, 'Возврат пособия от СФР', 'Средний', 'Здравствуйте. Социальный фонд России переводил пособие на моё счёт. Позвонили сейчас СФР, но нам сказали, что банк вернул деньги. Подскажите, почему? Когда звонили в банк узнать, могу ли я получать на свою карту пособие за жену, сказали, что можно. А сейчас выясняется, что нельзя. Это как так?'),
  ('noforward', 7, 'Ошибка при выдаче карты курьером', 'Средний', 'Здравствуйте, ко мне приехали и привезли карту. Но выдавало шибку и в приложении не показывало, что карта выдана. В итоге курьер уехал, сказал что нужно обратиться в сам офис, ещё и на встречу опоздал на целых 3 часа. Спасибо за потерянное время! Что мне теперь с этим всем делать?'),
  ('noforward', 8, 'Навязанная страховка по кредиту', 'Сложный', 'Здравстуйте! Я оформлят кредит месяц назад у вас в офисе, и сотрудники подключили мне страховку, о которой я не просил. Я сразу сказал, что никакие дополнительные услуги мне не нужны! Увидел сейчас, что у меня есть списание в АльфаСтрахование-Жизнь, что это ещё такое? Я согласия не давал, отменяйте списание, возвращайте деньги и отключайте все платные услуги!'),
  ('noforward', 9, 'Блокировка перевода по СБП', 'Сложный', 'Я уже битый час не могу провести перевод по СБП в другой банк, срочно нужно перевести 150 000 рублей, т.к. это возврат долга другу. А вы постоянно блокируете операцию и просите повторить её через 15 минут. Я ждал и 15, и 20, и 30 минут, весь день не даёт перевести. Сделайте уже что-нибудь!'),
  ('noforward', 10, 'Комиссия за пополнение в чужом банкомате', 'Средний', 'Здравствуйте! Сегодня я пополнила свою карту Альфа-Банка через банкомат ВТБ. С моего счета была списана комиссия в размере 150 рублей. При выдаче карты сотрудник банка заверил меня, что внесение наличных на карту Альфа-Банка через устройства любых других банков будет бесплатным. Однако по факту деньги списались. Просто немного непонятно, почему так?'),
  ('iknow', 1, 'Открытие вклада без визита в отделение', 'Лёгкий', 'Клиент спрашивает: «Могу ли я открыть вклад без визита в отделение?» Что вы ответите и что уточните?'),
  ('iknow', 2, 'Карта с кешбэком без платы за обслуживание', 'Средний', 'Клиент хочет карту с кешбэком, но не хочет платить за обслуживание. Какой продукт предложите и при каком условии обслуживание будет бесплатным?'),
  ('iknow', 3, 'Кредитная карта или потребительский кредит', 'Средний', 'Чем отличается кредитная карта от потребительского кредита? Клиент спрашивает: «Что мне выгоднее?»'),
  ('iknow', 4, 'Потеря карты и страх мошенничества', 'Средний', 'Клиент сообщает, что потерял карту и боится мошенничества. Перечислите все шаги, которые выполните прямо в этом звонке.'),
  ('iknow', 5, 'Смерть держателя основного счёта', 'Сложный', 'Клиент сообщает, что умер его супруг — держатель основного счёта. Что происходит со счётом и как действуете?'),
  ('iknow', 6, 'Клиент хочет уйти в другой банк', 'Средний', 'Клиент хочет закрыть счёт и уйти в другой банк. Как действуете — удерживаете или отпускаете? Что конкретно говорите?'),
  ('iknow', 7, 'Претензия о высоких ставках по кредитам', 'Средний', 'Клиент: «Я слышал, что у вас самые высокие ставки по кредитам. Зачем мне оставаться?» Как реагируете?'),
  ('iknow', 8, 'Стоит ли брать кредит сейчас', 'Средний', 'Клиент просит совета: «Стоит ли мне брать кредит прямо сейчас?» Вы отвечаете «да» или «нет»?'),
  ('iknow', 9, 'Не сообщили об изменении тарифа', 'Средний', 'Клиент возмущён: «Почему мне не сообщили об изменении тарифа?» Банк прав или нет?'),
  ('iknow', 10, 'Просьба перевести к специалисту', 'Средний', 'Клиент просит: «Переведите меня к специалисту, который знает больше». Правильный ответ — перевести?'),
  ('iknow', 11, 'Клиент хочет завершить диалог', 'Лёгкий', 'Клиент говорит: «Я уже всё понял, спасибо» и хочет завершить диалог. Вы завершаете?'),
  ('iknow', 12, 'Агрессия клиента без сути проблемы', 'Сложный', 'Клиент злится: «Вы все одинаковые, ничего не умеете!» Правильная реакция — извиниться?'),
  ('empathy', 1, 'Блокировка карты на кассе', 'Средний', 'Клиент звонит в банк в панике. Его карта была заблокирована в момент оплаты в супермаркете — прямо на кассе, при очереди. Клиент считает произошедшее унизительным и грозится закрыть все счета.

«Это просто позор! Меня поставили в неловкое положение перед людьми! Ваш банк заблокировал карту без каких-либо предупреждений! Я требую объяснений и компенсации!»'),
  ('empathy', 2, 'Скрытая комиссия и обвинение в воровстве', 'Сложный', 'Клиент заметил списание комиссии, о которой, по его словам, его никто не предупреждал. Он убеждён, что банк «тайно» снимает деньги, и чувствует себя обманутым.

«Вы воры! Сняли деньги без моего ведома! Я ничего не подписывал! Это мошенничество!»'),
  ('empathy', 3, 'Перевод не дошёл двое суток', 'Средний', 'Клиент сделал срочный перевод родственнику, деньги не пришли уже двое суток. Он беспокоится, нервничает и считает банк некомпетентным.

«Два дня! Два дня деньги висят где-то в воздухе! Это что, 19-й век?! Я перестану пользоваться вашим банком!»'),
  ('empathy', 4, 'Отказ в кредите лояльному клиенту', 'Сложный', 'Клиент получил отказ в кредите. Он считает, что у него хорошая история, и воспринимает отказ как личное оскорбление. Подозревает предвзятость.

«Я 10 лет клиент вашего банка, всегда платил вовремя! Почему отказ?! Вы предвзяты! Это дискриминация!»'),
  ('empathy', 5, 'Неверное имя в приложении', 'Средний', 'В мобильном приложении банка клиент обнаружил неверно указанное имя. Из-за этого он не может пройти верификацию и воспользоваться рядом функций. Раздражён, что уже звонит второй раз.

«Я уже неделю не могу пользоваться вашим приложением! Прошлый раз мне пообещали исправить — и ничего! Это безобразие!»'),
  ('empathy', 6, 'Банкомат не выдал деньги', 'Средний', 'Банкомат «съел» деньги: операция прошла, деньги списаны, но купюры не выданы. Клиент в стрессе, уверен, что деньги пропали.

«Ваш банкомат забрал мои деньги! Это форс-мажор! 5000 рублей просто исчезли! Верните немедленно!»'),
  ('empathy', 7, 'Навязанная страховка по кредиту', 'Сложный', 'Клиент увидел в договоре страховку, о которой его не предупредили при оформлении кредита. Он считает, что его обманули.

«Меня обманули при оформлении! Никто не говорил ни о какой страховке! Я хочу вернуть деньги и расторгнуть всё!»'),
  ('empathy', 8, 'Долгое ожидание на линии', 'Средний', 'Клиент ждал ответа оператора 45 минут. Когда наконец подключился оператор, он крайне раздражён и агрессивен ещё до того, как объяснил проблему.

«Сорок пять минут! Полчаса я слушал вашу музыку! Это что за сервис?! Вы вообще уважаете своих клиентов?!»'),
  ('empathy', 9, 'Подозрение на взлом счёта', 'Сложный', 'Клиент заметил несколько небольших незнакомых списаний. Он в панике, думает, что его взломали, и не понимает, что делать.

«Кто-то залез в мой счёт! Я вижу списания, которых не делал! Это конец! Куда исчезли мои деньги?!»'),
  ('empathy', 10, 'Задержка выдачи наличных по 115-ФЗ', 'Сложный', 'Клиент пришёл в отделение, чтобы получить наличные, но ему сообщили, что нужны дополнительные документы для верификации. Он считает, что банк «держит его деньги в заложниках».

«Это МОИ деньги! Я их честно заработал! Вы не имеете права их удерживать! Я пойду в суд и в ЦБ!»'),
  ('onecall', 1, 'Разблокировка карты после банкротства', 'Средний', 'Здравствуйте, у меня карта заблокирована была в связи с процедурой банкротства. Решение уже вынесено, и мне бы узнать, когда разблокируют ее. И если сейчас деньги будут поступать с зарплаты, они будут на счете? Ещё уточните, мне нужно в отделение банка обращаться, или я просто жду, когда разблокируют всё?'),
  ('onecall', 2, 'Перевод социально-защищённых средств', 'Средний', 'У меня есть социально-защищенные денежные средства на счете, 13 000 рублей. Почему я не могу перевести их по номеру телефона?'),
  ('onecall', 3, 'Досрочное погашение кредита', 'Лёгкий', 'Клиент хочет досрочно погасить кредит. Остаток долга — 87 000 руб. Спрашивает, нужно ли заявление, есть ли штраф и как получить справку о закрытии.'),
  ('onecall', 4, 'Звонок мошенников, назван CVV', 'Сложный', 'Клиент сообщает, что позвонил ''сотрудник службы безопасности'' и попросил сообщить CVV и код из СМС. Клиент успел назвать CVV, но код из СМС — нет. Спрашивает, что делать.'),
  ('onecall', 5, 'Перевод не тому получателю', 'Средний', 'Клиент перевёл 50 000 рублей не тому получателю — ошибся в одной цифре номера счёта. Деньги ушли 10 минут назад. Просит вернуть.'),
  ('onecall', 6, 'Отказ по кредиту без причины', 'Средний', 'Клиент получил отказ по заявке на  кредит через приложение. Обращение пришло без указания причины. Клиент возмущён и требует объяснений.'),
  ('onecall', 7, 'Двойное списание в ресторане', 'Средний', 'При оплате в ресторане сумма 4 500 рублей списана дважды. Клиент предоставил два чека. Деньги нужны срочно.'),
  ('onecall', 8, 'Ошибка входа в приложение', 'Средний', 'Клиент не может войти в приложение — пишет ошибка ''Доступ запрещён''. Смена пароля не помогает. Важен срочный платёж ЖКХ до конца дня.'),
  ('onecall', 9, 'Комиссия за обслуживание карты', 'Средний', 'Клиент обнаружил, что с него удержана комиссия 590 рублей за обслуживание карты. Считает, что карта у него бесплатная согласно рекламе. Требует возврата и объяснений.'),
  ('onecall', 10, 'Незнакомая транзакция ночью', 'Сложный', 'Клиент видит в истории транзакций платёж 12 000 рублей, которого он не совершал. Транзакция прошла вчера ночью через интернет-банк. Просит разобраться.'),
  ('onecall', 11, 'Открытие вклада пожилому клиенту', 'Средний', 'Клиент 72 лет хочет открыть вклад на 1 500 000 рублей. Видел рекламу ставки 18% годовых. Обращается в поддержку, чтобы уточнить условия и открыть в рамках диалога.'),
  ('onecall', 12, 'Уход клиента к конкуренту', 'Средний', 'Клиент заявляет, что уходит в другой банк, хочет закрыть карту, вклад и расчётный счёт. Причина — лучшие условия у конкурента.'),
  ('onecall', 13, 'Банкомат не выдал деньги', 'Средний', 'Клиент вставил карту в банкомат, деньги (20 000 руб.) не выданы, но со счёта списались. Банкомат сбросил операцию с ошибкой. Клиент сейчас стоит у банкомата.'),
  ('onecall', 14, 'Агрессивный клиент с угрозами', 'Сложный', 'Клиент звонит третий раз за день по одному вопросу (отказ в кредите). Кричит, оскорбляет сотрудника, угрожает жалобой в ЦБ и судом. Реальной новой информации по делу нет.'),
  ('onecall', 15, 'Ошибка вывода с Инвесткопилки', 'Средний', 'Клиент обращается в поддержку с недовольством, что все выходные не может вывести деньги с Инвесткопилки, потому что возникает ошибка. Грозится закрыть все счета и карты и уйти в другой банк.'),
  ('captains', 1, 'Блокировка карты в день зарплаты', 'Средний', 'Здравствуйте. Сегодня день зарплаты, мне на вашу карту пришли деньги. Я пошёл в магазин с семьёй, набрал продукты на 8 тысяч — а карта заблокирована. Я ничего не делал, никаких подозрительных операций. У меня в корзине продукты, жена с ребёнком ждёт. Мы что, должны голодать? За мной очередь стояла, в очень неудобное положение меня поставили!'),
  ('captains', 2, 'Возврат страховки по кредиту', 'Сложный', 'Здравствуйте, меня, кажется, обманули в офисе банка. Я 2 месяца назад оформлял у вас кредит на 5 лет в отделении, и там сотрудники подключили мне страховку. Сказали, что я могу отказаться от неё в любой момент и вернуть все деньги назад. А сейчас мне говорят, что отказаться от неё с возвратом денег можно только в первые 30 дней. Это что за обман?! Я вообще не планировал 5 лет этот кредит выплачивать, максимум за год закрою, а мне вперед пришлось страховку оплатить, которой я даже не воспользуюсь, получается?!'),
